import{_ as a,o as t,c as n,j as r,a as d,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const u=JSON.parse('{"title":"翼族人","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/星界边境/翼族人.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/星界边境/翼族人.md"}'),b={name:"4.资源分区/1.血统与训练/6.一次性血统/星界边境/翼族人.md"};function s(l,e,p,i,_,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"翼族人",tabindex:"-1"},[d("翼族人 "),r("a",{class:"header-anchor",href:"#翼族人","aria-label":'Permalink to "翼族人"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),o('<h1 id="翼族人-1" tabindex="-1">翼族人 <a class="header-anchor" href="#翼族人-1" aria-label="Permalink to &quot;翼族人&quot;">​</a></h1><p>翼族人（Avian）<br> 科技本质<br> 一次性血统<br> 原典：原典：《星界边境（Starbound）》<br> 描述：来自阿沃斯星球的鸟状人形种族，他们的建筑采用原始的石头结构、简单的服装、深厚的宗教性质和相当简单的战斗策略（主要包括“用数千名一次性士兵压倒敌人”）使他们乍一看似乎很原始。<br> 但翼族人非常聪明，任何勇敢或愚蠢的人冒险进入翼族人神庙或坟墓都会发现由 Avolite 水晶提供动力的先进且致命的技术的例子。<br> 这些神秘的能源仅由观星者牧师在他们的母星上开采，为从简单的灯光到能够进行星际旅行的宇宙飞船的一切提供动力。</p><p>翼族人文化主要涉及到Aether的有翼之神Kluex。<br> 翼族人相信自己因为进入凡世而被剥夺了双翼，只有前往来生后才能通过对神明的敬拜重获飞翔的能力。<br> 在其历史中，翼族人一直是个较为原始的种族，没有什么科学发展。<br> 就在翼族人族开始衰败时，某个对此感到惋惜的高等种族将高等技术传授给了他们。<br> 这项新科技让翼族人族得以在宇宙中旅行并繁衍后代，并在所到之处建立了敬奉神明的庙宇。<br> 翼族人只能通过摆脱他们的凡人身体，同时在心中保持最真实的信仰来与 Kluex 团聚。达到这种纯洁状态的仪式包括对被俘虏的敌人进行仪式性的祭祀，以及精心设计的游行，最终由祭司挑选的最虔诚的人爬上高塔，进行信仰的飞跃，他们的灵魂从凡人的牢笼中挣脱出来，飞入以太，而他们现在被丢弃的身体则坠落到下面的地面上。<br> 然而，这种血腥的神学并不适合所有翼族人，越来越多的人拒绝了观星者的话语和 Kluex 的神性。他们自称“Grounded（居于地上者（陆行鸟（x）”，已经飞向星空并形成了自己的殖民地。有些人制作了陆地飞行船，以海盗为生，也有部分翼族人加入了其他多元化的多种族组织。</p><p>翼族人有大量的神话典籍，将其奉为绝对的经典。在社会体制上，传统翼族社会比较接近现实中的古埃及文明，由观星者与类似法老的大祭司统治，并且积极修建宏伟的陵墓与庞大的神庙，他们的祭祀活动其实就是让翼族人从高空一跃而下，享受自由落体带来的片刻“飞行”的刺激，并且在祭品落地时伴随着声响欢呼，他们从宗教角度的理解中，这种祭祀不是真正的死亡，而是离开肉体的拘束获得自由自在飞行的恩赐。<br> 更加“接地气”的行者社会中，翼族人摈弃了对飞行的渴求，专心致志地发展更加稳定但难以发展的村落，他们会积极地与外来者接触、贸易和学习，并且自身也会向外探索，踏足更多从未记载的地区。<br> 而通过宇宙飞船等外力真正飞起来的翼族人则在太空中大量的作为战斗人员存在，翼族人天生骁勇善战，并且在战斗中表现出了极佳的反应速度与含不畏死的凶狠，这使得他们在宇宙海盗和雇佣兵行业混的风生水起，也有翼族人加入其他种族部队从军，或者在某个宇宙空间站当保安的情况。</p><p>被引力束缚者<br> D+600<br> 翼族人的外观是一种类人型鸟类，在外观上，翼族人的头部都类似于地球上的鸟类，并且种类多样，而且与常见的野生鸟类逻辑不同的是，无论雌雄，翼族人的羽毛颜色都可以生的非常艳丽（但大部分情况下依然是雄性更加美丽娇嫩，而雌性更加强壮）。<br> 如果整个遗传谱系都是比较朴素的羽色，那新生代的翼族人也会在外观上平平无奇，雄性新生儿会继承母系的鸟类特征与毛色，雌性则继承父系，也会出现隔代返祖现象（此时，雄性新生儿继承母系的父代特征，雌性则继承父系的母代特征）；由于这种特性，翼族人的观念中，头骨的形状越是优美，羽色越是华丽的翼族人就更为高贵，因为这些翼族的谱系中会有更加久远与高贵的血脉继承。<br> 丑小鸭生出白天鹅的情节在翼族社会完全就是可能发生的现实。<br> 翼族人的四肢是困扰翼族演化学界的一大难题，这些人形鸟类的足部是鸟类的爪子，但在大腿与小腿的结构上却依然呈现了与人类相同的构造，双手都会覆盖一层羽毛，却有着与人科物种相同的骨骼结构与五指手掌，而有极少部分的翼族人会在小臂上生长出优美的鸟类飞羽，甚至是臀部上方出现的飞羽，但这些优美的羽毛除了观赏性之外毫无用处。<br> 虽然是卵生物种，与鸟类的泄殖腔不同，翼族人确实拥有与哺乳动物相同的生殖系统，他们也拥有哺乳的能力，具体来说，他们是一种卵生哺乳类人形鸟类。<br> 由于其物种早期文明在原始阶段经历了太过于漫长的时间，导致目前对于翼族人的演化路线依然成谜。<br> 与他们的类人外表与身体结构表现不同的一点是，他们的关节依然有着鸟类的柔软，部分翼族人（如具有猫头鹰外表的那些）可以将脖子扭转至多180°，骨骼比起坚硬更像是柔韧，并且有一定的中空结构，肌肉密度极高，导致所有的翼族人在相同的体重上无论男女会比其他物种看起来更加的纤细（翼族的雄性也经常会被误认为是翼族少女），虽然这导致翼族人在钝击与挥砍伤害上具有1点伤害易伤，但他们却反常地擅长战斗，翼族人的移动速度额外提升10米，在生理属性上具有2dp内在加值的同时，在敏捷属性检定上额外获得1点附加成功。并且，每具有1点传奇敏捷，就会在生理属性上再获得1dp内在加值并提升5米移动速度。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const f=a(b,[["render",s]]);export{u as __pageData,f as default};
